// Stage 8.5.7 — Shared Engine Dry Run
// Extracts booking fields from the incoming webhook body.
// In the live flow these come from the WhatsApp parser + Airtable session state.
// In this dry-run fork we extract them from the POST body directly.
//
// GAP: selected_bed_codes is NOT in the current live bot session state.
// The live flow assigns beds via a separate Airtable lookup (Search Active Beds - WA).
// For this dry-run we use staging placeholder DEMO-R1-B1.
// Auto-assignment from availability is the NEXT slice (Stage 8.5.8).
// Do NOT treat this placeholder as production-safe.

const body = $input.first().json.body || $input.first().json;

const phone        = String(body.phone        || '+34999000000').trim();
const guestName    = String(body.guest_name   || body.name || '').trim() || null;
const email        = String(body.email        || '').trim() || null;
const checkIn      = String(body.check_in     || '').trim() || null;
const checkOut     = String(body.check_out    || '').trim() || null;
const guestCount   = parseInt(body.guest_count || '1', 10) || 1;
const packageCode  = String(body.package_code || 'malibu').trim();
const roomType     = String(body.room_type    || 'shared').trim();
const paymentChoice = String(body.payment_choice || 'deposit').trim();
const addOns       = Array.isArray(body.add_ons) ? body.add_ons : [];
const language     = String(body.language     || 'en').trim();
const clientSlug   = String(body.client_slug  || 'wolfhouse-somo').trim();

// GAP: selected_bed_codes must come from a bed availability query.
// Staging dry-run uses DEMO-R1-B1 as a placeholder.
// Production slice (8.5.8) must call /staff/availability-report or equivalent
// to pick real available beds before calling /staff/bot/bookings/create.
const selectedBedCodes = Array.isArray(body.selected_bed_codes) && body.selected_bed_codes.length > 0
  ? body.selected_bed_codes
  : ['DEMO-R1-B1']; // dry-run staging placeholder only

return [{
  json: {
    phone,
    guest_name: guestName,
    email,
    check_in: checkIn,
    check_out: checkOut,
    guest_count: guestCount,
    package_code: packageCode,
    room_type: roomType,
    payment_choice: paymentChoice,
    add_ons: addOns,
    language,
    client_slug: clientSlug,
    source: 'luna_whatsapp',
    selected_bed_codes: selectedBedCodes,
    _dry_run: true,
    _gap_selected_bed_codes: 'staging placeholder DEMO-R1-B1 — auto-assignment is Stage 8.5.8'
  }
}];

// Stage 8.5.7 — Draft payment link reply (WhatsApp NOT sent in dry-run)
// In live flow this message would be sent to the guest via WhatsApp.
// The checkout_url comes from the shared Staff API Stripe endpoint;
// Stripe is NOT called directly from n8n.

const stripeResult = $input.first().json;
const bookingCreate = $('HTTP - Bot Booking Create').first().json;
const bookingPreview = $('HTTP - Bot Booking Preview').first().json;

const checkoutUrl    = stripeResult.checkout_url || '';
const bookingCode    = stripeResult.booking_code  || bookingCreate.booking_code || '';
const amountCents    = stripeResult.amount_due_cents || 0;
const currency       = (stripeResult.currency || 'eur').toUpperCase();
const paymentStatus  = stripeResult.payment_status || '';
const paymentChoice  = bookingCreate.quote?.payment_choice || 'deposit';

const amountStr = (amountCents / 100).toFixed(2) + ' ' + currency;

const isDeposit = paymentChoice === 'deposit';
const paymentLabel = isDeposit ? 'deposit' : 'full amount';

const replyDraft = [
  '✅ Great! Your Wolfhouse booking is confirmed: ' + bookingCode + '.',
  '',
  'To secure your spot, please pay the ' + paymentLabel + ' of ' + amountStr + ' via this secure Stripe payment link:',
  '',
  checkoutUrl,
  '',
  'The link expires in 24 hours. Once paid, you will receive a confirmation. 🏄'
].join('\n');

return [{
  json: {
    dry_run: true,
    whatsapp_sent: false,
    no_payment_truth_recorded: true,
    booking_code: bookingCode,
    payment_id: stripeResult.payment_id,
    booking_id: stripeResult.booking_id,
    checkout_url: checkoutUrl,
    amount_due_cents: amountCents,
    currency,
    payment_status: paymentStatus,
    reply_draft: replyDraft,
    note: 'DryRun Stage 8.5.7: WhatsApp send bypassed. Stripe called via Staff API, not directly from n8n. STRIPE_DEFAULT_DEPOSIT_CENTS NOT used.',
    _proof_no_direct_stripe: true,
    _proof_no_stripe_default_deposit_cents: true,
    _proof_sends_whatsapp_false: true
  }
}];
